   105→class ProfileStorageImpl extends ProfileStorage {
   106→  final SharedPreferences _sharedPreferences;
   107→  final FlutterSecureStorage _secureStorage = const FlutterSecureStorage();
   108→
   109→  ProfileStorageImpl(this._sharedPreferences);
   110→
   111→  Future<bool> _updateStringValueOnSecureStorage(
   112→      String key, String? value) async {
   113→    if (value != null) {
   114→      await _secureStorage.write(key: key, value: value);
   115→    } else {
   116→      await _secureStorage.delete(key: key);
   117→    }
   118→    return true;
   119→  }
   120→
   121→  Future<String?> _readStringValueOnSecureStorage(String key) async {
   122→    // FlutterSecureStorage.read causes a PlatformException for undefined keys.
   123→    if (await _secureStorage.containsKey(key: key)) {
   124→      return _secureStorage.read(key: key);
   125→    } else {
   126→      return null;
   127→    }
   128→  }
   129→
   130→  ///////////////////////////////////////////////////////////////////////////
   131→  // Setters
   132→  ///////////////////////////////////////////////////////////////////////////
   133→
   134→  @override
   135→  Future<bool> setTerminalId(String terminalId) async {
   136→    return _sharedPreferences.setString(
   137→        ProfileStorage.prefsKeyTerminalId, terminalId);
   138→  }
   139→
   140→  @override
   141→  Future<bool> setEmail(String? email) async {
   142→    await _updateStringValueOnSecureStorage(
   143→        ProfileStorage.prefsKeyEmail, email);
   144→    return true;
   145→  }
   146→
   147→  @override
   148→  Future<bool> setPassword(String? password) async {
   149→    await _updateStringValueOnSecureStorage(
   150→        ProfileStorage.prefsKeyPassword, password);
   151→    return true;
   152→  }
   153→
   154→  @override
   155→  Future<bool> setUserBirthday(DateTime? birthday) async {
   156→    await _updateStringValueOnSecureStorage(
   157→      ProfileStorage.prefsKeyUserBirthday,
   158→      birthday != null ? _dateOnly(birthday) : null,
   159→    );
   160→    return true;
   161→  }
   162→
   163→  @override
   164→  Future<bool> setTeamId(String? teamId) {
   165→    if (teamId != null) {
   166→      return _sharedPreferences.setString(
   167→          ProfileStorage.prefsKeyTeamId, teamId);
   168→    } else {
