    );
    if (result.hasLeft) {
      return Left(result.left);
    }

    // Sign out and clear all cached data after successful account deletion
    await Future.wait([
      AuthUtils.instance.signOut(),
      _profileStorage.setUserId(null),
      _profileStorage.setTeamId(null),
      _profileStorage.setEmail(null),
      _profileStorage.setPassword(null),
      _profileStorage.setIsInSignUpFlow(false),
    ]);

    return const Right(true);
  }

  @override
  Future<bool> get isLoggedIn async {
    return await AuthUtils.instance.isSignedIn();
  }
}

